export declare const DOC_TEMPLATE = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>{{TITLE}}</title>\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/styles/atom-one-dark.min.css\">\n    <style>\n        :root {\n            --bg: #0d1117;\n            --surface: #161b22;\n            --border: #30363d;\n            --text: #c9d1d9;\n            --muted: #8b949e;\n            --accent: #58a6ff;\n            --code-bg: #161b22;\n        }\n\n        * { box-sizing: border-box; }\n\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Helvetica, Arial, sans-serif;\n            background: var(--bg);\n            color: var(--text);\n            line-height: 1.7;\n            margin: 0;\n            padding: 2rem 1rem;\n        }\n\n        .doc-container {\n            max-width: 880px;\n            margin: 0 auto;\n            padding: 2rem;\n            background: var(--surface);\n            border: 1px solid var(--border);\n            border-radius: 12px;\n        }\n\n        h1 {\n            font-size: 2rem;\n            border-bottom: 1px solid var(--border);\n            padding-bottom: 0.5rem;\n            margin-top: 0;\n        }\n\n        h2 {\n            font-size: 1.5rem;\n            margin-top: 2rem;\n            color: var(--accent);\n        }\n\n        h3 { font-size: 1.2rem; margin-top: 1.5rem; }\n\n        p { margin: 0.75rem 0; }\n\n        a { color: var(--accent); }\n\n        table {\n            width: 100%;\n            border-collapse: collapse;\n            margin: 1rem 0;\n        }\n\n        th, td {\n            border: 1px solid var(--border);\n            padding: 0.6rem 0.8rem;\n            text-align: left;\n        }\n\n        th { background: var(--bg); color: var(--accent); }\n\n        ul, ol { margin: 0.75rem 0; padding-left: 1.5rem; }\n\n        li { margin: 0.25rem 0; }\n\n        code {\n            font-family: \"SFMono-Regular\", Consolas, \"Liberation Mono\", Menlo, monospace;\n            background: var(--code-bg);\n            padding: 0.15rem 0.35rem;\n            border-radius: 4px;\n            font-size: 0.9em;\n        }\n\n        pre {\n            background: var(--code-bg);\n            border: 1px solid var(--border);\n            border-radius: 8px;\n            padding: 1rem;\n            overflow-x: auto;\n        }\n\n        pre code {\n            background: transparent;\n            padding: 0;\n            border-radius: 0;\n            font-size: 0.85em;\n        }\n\n        .signature {\n            background: var(--code-bg);\n            border-left: 4px solid var(--accent);\n            padding: 1rem;\n            border-radius: 0 8px 8px 0;\n            margin: 1rem 0;\n            font-family: \"SFMono-Regular\", Consolas, \"Liberation Mono\", Menlo, monospace;\n        }\n\n        .signature pre {\n            background: transparent;\n            border: none;\n            padding: 0;\n            margin: 0;\n        }\n\n        .signature code {\n            background: transparent;\n            padding: 0;\n        }\n\n        footer {\n            margin-top: 2rem;\n            padding-top: 1rem;\n            border-top: 1px solid var(--border);\n            color: var(--muted);\n            font-size: 0.85rem;\n        }\n    </style>\n</head>\n<body>\n    <article class=\"doc-container\">\n        {{CONTENT}}\n        <footer>Generated by code-check</footer>\n    </article>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/highlight.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/languages/typescript.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/languages/go.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/languages/rust.min.js\"></script>\n    <script>\ndocument.querySelectorAll('.signature code').forEach(el => hljs.highlightElement(el));\nhljs.highlightAll();\n</script>\n</body>\n</html>\n";
